import type { SamplingResult } from '@opentelemetry/sdk-trace-node';
import { O11yMetrics } from '../common/metric';
/**
 * Represents the SamplerTelemetry class which extends O11yMetrics.
 * This class provides metrics related to the Sampler's behavior.
 * @class
 * @extends {O11yMetrics}
 */
export default class SamplerTelemetry extends O11yMetrics {
    /**
     * Represents the metric `started.spans`.
     * This metric represents the number of spans that were started by the Sampler.
     * @type {Counter}
     * @private
     * @readonly
     */
    private readonly _startedSpansCounter;
    /**
     * Creates an instance of SamplerTelemetry.
     */
    constructor();
    /**
     * Increments the metric `started.spans` by 1 and adds attributes for sampling decision, technology, and sdkVersion.
     * @param samplingResult The sampling result containing the decision.
     */
    incrementStartedSpansCounter: (samplingResult: SamplingResult) => void;
}
